1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	const BLOCK_BASE = 60;
19	const BLOCK_SIZE = 3;
20	
21	function withFirstInsurance(base: number): number {
22	  return base + base * FIRST_INSURANCE_SURCHARGE;
23	}
24	
25	function itemBase(item: Item): number {
26	  return BASE_PREMIUMS[item.type];
27	}
28	
29	function groupByType(items: Item[]): Map<string, Item[]> {
30	  const groups = new Map<string, Item[]>();
31	  for (const item of items) {
32	    const list = groups.get(item.type) ?? [];
33	    list.push(item);
34	    groups.set(item.type, list);
35	  }
36	  return groups;
37	}
38	
39	function componentGroupBase(group: Item[]): number {
40	  const blocks = Math.floor(group.length / BLOCK_SIZE);
41	  const remainder = group.length - blocks * BLOCK_SIZE;
42	  return blocks * BLOCK_BASE + remainder * itemBase(group[0]);
43	}
44	
45	function componentsTotal(items: Item[]): number {
46	  let total = 0;
47	  for (const [, group] of groupByType(items)) {
48	    total += withFirstInsurance(componentGroupBase(group));
49	  }
50	  return total;
51	}
52	
53	function quotePremium(items: Item[]): number {
54	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
55	  const others = items.filter((item) => !COMPONENT_TYPES.has(item.type));
56	  const othersTotal = others.reduce(
57	    (sum, item) => sum + withFirstInsurance(itemBase(item)),
58	    0,
59	  );
60	  return Math.ceil(othersTotal + componentsTotal(components) + PROCESSING_FEE);
61	}
62	
63	export function runScenario(scenario: Scenario): { results: { premium: number }[] } {
64	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
65	  return { results };
66	}
