function itemPremium(item: Item): number {
  const base = itemBase(item);
  const curseSurcharge = item.cursed ? base * 0.5 : 0;
  return withFirstInsurance(base) + curseSurcharge;
}

function quotePremium(items: Item[]): number {
  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
  const others = items.filter((item) => !COMPONENT_TYPES.has(item.type));
  const othersTotal = others.reduce(
    (sum, item) => sum + itemPremium(item),
    0,
  );
  return Math.ceil(othersTotal + componentsTotal(components) + PROCESSING_FEE);
}
